form:Form.form:Scripts:
		
function EnableButtons()
{ 
	CtrlEnabled("PERSONA",Ctrl("GRID").RowsCount()?true:false);
	CtrlEnabled("LEGAJO",Ctrl("GRID").RowsCount()?true:false);
	CtrlEnabled("REPORTE",Ctrl("GRID").RowsCount()?true:false);
}

function SearchText()
{                    
	Ctrl("GRID").filter("",Ctrl("buscar").GetCValue());
	EnableButtons();
}

function ObjtectResult() {
	this.processResult = function(xmlin) {        
		Ctrl("main").DoEvent("REFRESH");
	}
}                   

function ShowPersonal()
{                          
	openNewFlowWait("NucleusRH.Base.Personal.Legajo.flow","ORGANIGRAMA",'<ID VALUE="'+Ctrl("GRID").GetSelectAttrValue("oi_personal")+'" />',new ObjtectResult(),"L");
}

function ShowLegajo()
{                      
	openNewFlowWait("NucleusRH.Base.Personal.LegajoEmpresa.flow","ORGANIGRAMA",'<ID VALUE="'+Ctrl("GRID").GetSelectAttrValue("oi_personal_emp")+'" />',new ObjtectResult(),"L");
}

function ShowReporte()
{
	openNewFlowWait("NucleusRH.Base.Personal.Reportes.Legajo.flow","ORGANIGRAMA",'<ID VALUE="'+Ctrl("GRID").GetSelectAttrValue("oi_personal_emp")+'" />',new ObjtectResult(),"L");
}
